import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingCart, Bell, Menu, X, LogOut, LayoutDashboard, User } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import API from '../utils/api';

function Logo({ size = 32 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" fill="none">
      <circle cx="50" cy="50" r="44" stroke="url(#nr2)" strokeWidth="5" fill="none"/>
      <rect x="4"  y="46" width="18" height="8" rx="3" fill="url(#nb2)"/>
      <rect x="2"  y="42" width="6"  height="16" rx="2" fill="#67e8f9"/>
      <rect x="78" y="46" width="18" height="8" rx="3" fill="url(#nb2)"/>
      <rect x="92" y="42" width="6"  height="16" rx="2" fill="#67e8f9"/>
      <polygon points="50,18 28,75 72,75" fill="url(#nt2)"/>
      <polygon points="50,40 40,65 60,65" fill="#0b0c0e"/>
      <defs>
        <linearGradient id="nt2" x1="28" y1="18" x2="72" y2="75" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#22d3ee"/><stop offset="100%" stopColor="#818cf8"/>
        </linearGradient>
        <linearGradient id="nr2" x1="0" y1="0" x2="100" y2="100" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#22d3ee"/><stop offset="100%" stopColor="#475569"/>
        </linearGradient>
        <linearGradient id="nb2" x1="0" y1="0" x2="1" y2="0" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#67e8f9"/><stop offset="100%" stopColor="#475569"/>
        </linearGradient>
      </defs>
    </svg>
  );
}

const navLinks = [
  { label: 'Exercises', path: '/exercises' },
  { label: 'Diet',      path: '/diet' },
  { label: 'Transform', path: '/transformations' },
  { label: 'Store',     path: '/store' },
  { label: 'About',     path: '/about' },
  { label: 'Enquiry',   path: '/enquiry' },
];

export default function Navbar() {
  const { user, logout } = useAuth();
  const { count } = useCart();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [unread, setUnread] = useState(0);

  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', h);
    return () => window.removeEventListener('scroll', h);
  }, []);

  useEffect(() => {
    if (user) {
      API.get('/notifications').then(r => setUnread(r.data.filter(n => !n.isRead).length)).catch(() => {});
    }
  }, [user, location.pathname]);

  const handleLogout = () => { logout(); navigate('/'); setMobileOpen(false); };
  const isActive = (path) => location.pathname === path;

  return (
    <>
      <motion.nav
        initial={{ y: -80 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'nav-float shadow-lg shadow-black/30' : 'bg-transparent'}`}
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6">
          <div className="flex items-center justify-between h-16">

            {/* Logo */}
            <Link to="/" className="flex items-center gap-2.5 flex-shrink-0 group">
              <motion.div whileHover={{ rotate: 10 }} transition={{ type: 'spring', stiffness: 300 }}>
                <Logo size={34} />
              </motion.div>
              <div className="leading-none">
                <div className="text-white font-black gym-font text-lg tracking-widest">FITNATION</div>
                <div className="text-[#22d3ee] font-bold text-[9px] tracking-[3px]">BY AJEET</div>
              </div>
            </Link>

            {/* Desktop Nav Links */}
            <div className="hidden lg:flex items-center gap-0.5">
              {navLinks.map(l => (
                <Link key={l.path} to={l.path}
                  className={`px-3.5 py-2 rounded-lg text-sm font-medium transition-all relative ${
                    isActive(l.path)
                      ? 'text-[#22d3ee]'
                      : 'text-gray-400 hover:text-white'
                  }`}
                >
                  {l.label}
                  {isActive(l.path) && (
                    <motion.div layoutId="nav-indicator"
                      className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#22d3ee] rounded-full"
                    />
                  )}
                </Link>
              ))}
            </div>

            {/* Right Actions */}
            <div className="hidden lg:flex items-center gap-2">
              {/* Cart */}
              <Link to="/cart" className="relative p-2 rounded-xl text-gray-400 hover:text-[#22d3ee] hover:bg-white/5 transition-all">
                <ShoppingCart size={19} />
                {count > 0 && (
                  <motion.span initial={{ scale: 0 }} animate={{ scale: 1 }}
                    className="absolute -top-0.5 -right-0.5 w-4.5 h-4.5 min-w-[18px] min-h-[18px] bg-[#22d3ee] text-black text-[9px] font-bold rounded-full flex items-center justify-center">
                    {count}
                  </motion.span>
                )}
              </Link>

              {user ? (
                <>
                  {/* Notifications */}
                  <Link to="/notifications" className="relative p-2 rounded-xl text-gray-400 hover:text-[#22d3ee] hover:bg-white/5 transition-all">
                    <Bell size={19} />
                    {unread > 0 && (
                      <span className="absolute -top-0.5 -right-0.5 min-w-[16px] h-4 bg-red-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center px-0.5">{unread}</span>
                    )}
                  </Link>

                  {/* User pill */}
                  <div className="flex items-center gap-2 px-2.5 py-1.5 rounded-xl border border-white/8 bg-white/4 hover:bg-white/7 transition-all">
                    <div className="w-7 h-7 rounded-full bg-gradient-to-br from-[#22d3ee] to-[#818cf8] flex items-center justify-center text-black font-bold text-xs">
                      {user.name?.[0]?.toUpperCase()}
                    </div>
                    <div className="leading-none">
                      <div className="text-white text-xs font-semibold">{user.name?.split(' ')[0]}</div>
                      <div className="text-[#22d3ee] text-[9px] capitalize">{user.role}</div>
                    </div>
                  </div>

                  {(user.role === 'admin' || user.role === 'trainer') ? (
                    <Link to="/admin" className="btn-fire text-xs px-4 py-2 gap-1.5">
                      <LayoutDashboard size={13} /> Panel
                    </Link>
                  ) : (
                    <Link to="/dashboard" className="btn-fire text-xs px-4 py-2">Dashboard</Link>
                  )}

                  <button onClick={handleLogout} className="p-2 rounded-xl text-gray-500 hover:text-red-400 hover:bg-red-500/8 transition-all">
                    <LogOut size={17} />
                  </button>
                </>
              ) : (
                <Link to="/login" className="btn-fire text-sm px-5 py-2">Sign In</Link>
              )}
            </div>

            {/* Mobile hamburger */}
            <div className="flex items-center gap-2 lg:hidden">
              {count > 0 && (
                <Link to="/cart" className="relative p-2 text-gray-400">
                  <ShoppingCart size={20} />
                  <span className="absolute -top-0.5 -right-0.5 w-4 h-4 bg-[#22d3ee] text-black text-[9px] font-bold rounded-full flex items-center justify-center">{count}</span>
                </Link>
              )}
              <button onClick={() => setMobileOpen(!mobileOpen)}
                className="p-2 rounded-xl text-gray-400 hover:text-white hover:bg-white/8 transition-all">
                {mobileOpen ? <X size={22} /> : <Menu size={22} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        <AnimatePresence>
          {mobileOpen && (
            <motion.div
              initial={{ opacity: 0, y: -12 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -12 }}
              transition={{ duration: 0.2 }}
              className="lg:hidden border-t border-white/8 bg-[#0b0c0e]/95 backdrop-blur-xl"
            >
              <div className="px-4 py-4 space-y-1">
                <Link to="/" onClick={() => setMobileOpen(false)}
                  className={`block px-4 py-2.5 rounded-xl text-sm font-medium transition-all ${isActive('/') ? 'text-[#22d3ee] bg-[#22d3ee]/8' : 'text-gray-300 hover:text-white hover:bg-white/5'}`}>
                  Home
                </Link>
                {navLinks.map(l => (
                  <Link key={l.path} to={l.path} onClick={() => setMobileOpen(false)}
                    className={`block px-4 py-2.5 rounded-xl text-sm font-medium transition-all ${isActive(l.path) ? 'text-[#22d3ee] bg-[#22d3ee]/8' : 'text-gray-300 hover:text-white hover:bg-white/5'}`}>
                    {l.label}
                  </Link>
                ))}
                <div className="pt-3 border-t border-white/8 space-y-2">
                  {user ? (
                    <>
                      <div className="flex items-center gap-3 px-4 py-2">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-[#22d3ee] to-[#818cf8] flex items-center justify-center text-black font-bold text-sm">
                          {user.name?.[0]?.toUpperCase()}
                        </div>
                        <div>
                          <div className="text-white text-sm font-semibold">{user.name}</div>
                          <div className="text-[#22d3ee] text-xs capitalize">{user.role}</div>
                        </div>
                      </div>
                      {(user.role === 'admin' || user.role === 'trainer')
                        ? <Link to="/admin" onClick={() => setMobileOpen(false)} className="btn-fire w-full py-3 text-sm">Admin Panel</Link>
                        : <Link to="/dashboard" onClick={() => setMobileOpen(false)} className="btn-fire w-full py-3 text-sm">My Dashboard</Link>
                      }
                      <button onClick={handleLogout} className="w-full text-left px-4 py-2.5 text-sm text-red-400 flex items-center gap-2 rounded-xl hover:bg-red-500/8 transition-all">
                        <LogOut size={15} /> Sign Out
                      </button>
                    </>
                  ) : (
                    <Link to="/login" onClick={() => setMobileOpen(false)}>
                      <button className="btn-fire w-full py-3 text-sm">Sign In</button>
                    </Link>
                  )}
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.nav>
    </>
  );
}
